function renderPriceOutlook(model=priceOutlookCache.get(state.marketSymbol),loading=false,error=false){
  const panel=$('#priceOutlookPanel');if(!panel)return;setText('#outlookTitle',`Projeção ${displayPair()}`);const status=$('#outlookStatus');status.classList.toggle('error',!!error);status.innerHTML=loading?'<i></i> CALCULANDO':error?'<i></i> INDISPONÍVEL':model?'<i></i> ATUALIZADO':'<i></i> AGUARDANDO';if(!model){[1,7,30].forEach(days=>{setText(`#outlookPrice${days}d`,'—');setText(`#outlookChange${days}d`,'—');setText(`#outlookRange${days}d`,'Faixa provável: —');const meter=$(`#outlookMeter${days}d`);if(meter){meter.style.width='0';meter.className=''}});setText('#outlookUpdated',loading?'Consultando candles diários da Binance':'Histórico diário indisponível');return}
  const base=state.currentPrice>0?state.currentPrice:model.sourceClose;[1,7,30].forEach(days=>{const effectiveDays=days/(1+days/45),change=Math.exp(model.drift*effectiveDays)-1,price=base*(1+change),spread=Math.min(.65,model.volatility*Math.sqrt(days)*1.05),low=price*Math.exp(-spread),high=price*Math.exp(spread),changePct=change*100;setText(`#outlookPrice${days}d`,formatPrice(price));const changeElement=$(`#outlookChange${days}d`);changeElement.textContent=`${changePct>=0?'+':''}${changePct.toFixed(2).replace('.',',')}%`;changeElement.className=changePct>=0?'positive':'negative';setText(`#outlookRange${days}d`,`Faixa provável: ${formatPrice(low)} – ${formatPrice(high)}`);const meter=$(`#outlookMeter${days}d`),width=Math.min(50,Math.max(3,Math.abs(changePct)*5));meter.style.width=`${width}%`;meter.style.marginLeft=changePct>=0?'50%':`${50-width}%`;meter.className=changePct>=0?'':'negative'});setText('#outlookUpdated',`${model.dataPoints} candles · ${new Date(model.calculatedAt).toLocaleTimeString('pt-BR',{hour:'2-digit',minute:'2-digit'})}`)
}
async function loadPriceOutlook(force=false){
  const symbol=state.marketSymbol,cached=priceOutlookCache.get(symbol);if(!force&&cached&&Date.now()-cached.calculatedAt<300000){renderPriceOutlook(cached);return cached}const request=++priceOutlookRequest;renderPriceOutlook(cached,true);try{const rows=await fetchBinance(`/api/v3/klines?symbol=${encodeURIComponent(symbol)}&interval=1d&limit=120`);if(!Array.isArray(rows))throw new Error('Candles diários inválidos');const model=calculateDailyOutlook(rows);priceOutlookCache.set(symbol,model);if(request===priceOutlookRequest&&symbol===state.marketSymbol)renderPriceOutlook(model);return model}catch(error){if(request===priceOutlookRequest&&symbol===state.marketSymbol)renderPriceOutlook(cached,false,true);return null}
}

async function fetchBinance(path){let lastError;for(const base of BINANCE_BASES){const controller=new AbortController(),timer=setTimeout(()=>controller.abort(),8000);try{const response=await fetch(base+path,{signal:controller.signal});if(!response.ok)throw new Error(`Binance ${response.status}`);return await response.json()}catch(error){lastError=error}finally{clearTimeout(timer)}}throw lastError||new Error('API indisponível')}
function hasFreshPrice(){return state.dataSource==='binance'&&Number.isFinite(state.currentPrice)&&state.currentPrice>0&&Date.now()-state.lastPriceAt<=PRICE_STALE_MS}
function executionPrice(side='last'){if(!hasFreshPrice())return 0;if(side==='buy')return Number(state.quote.ask)||state.currentPrice;if(side==='sell')return Number(state.quote.bid)||state.currentPrice;return Number(state.quote.last)||state.currentPrice}
function setMarketConnection(status,message){
  const changed=state.dataSource!==status;state.dataSource=status;const live=status==='binance';
  setText('#statSource',live?`Binance Spot · ${displayCurrency()} · agora`:message);
  setText('#exchangeStatus',live?'Binance Spot':status==='loading'?'Conectando...':'Dados indisponíveis');
  setText('#marketConnectionStatus',live?'● Binance em tempo real':status==='loading'?'● Conectando à Binance':'● Mercado pausado · sem cotação');
  setText('#liveStatus',live?'● AO VIVO':status==='loading'?'CONECTANDO':'PAUSADO');
  $('#liveStatus')?.classList.toggle('offline',!live);$('#simulateBtn').disabled=!live;const start=$('#startRobot');if(start&&!state.robot.active&&!state.robot.starting)start.disabled=!live;if(!live&&state.order.active&&$('#progressLabel')){$('#progressLabel').textContent='PAUSADO';$('#progressLabel').className='paused'}if(!live&&state.robot.position)renderRobotUI();if(changed)drawChart();
}
function rollLiveCandle(price,time=Date.now(),volume=0){
  if(!candles.length)return;const interval=timeframeMs[state.timeframe]||900000,bucket=Math.floor(time/interval)*interval,roll=(series,maxLength)=>{if(!series.length)return;const last=series.at(-1);if(Number(last.time)<bucket){const open=last.close;series.push({time:bucket,open,high:Math.max(open,price),low:Math.min(open,price),close:price,volume:Math.max(0,volume)});while(series.length>maxLength)series.shift()}else{last.close=price;last.high=Math.max(last.high,price);last.low=Math.min(last.low,price);last.volume=Math.max(0,Number(last.volume)||0)+Math.max(0,volume)}};roll(analysisCandles,320);roll(candles,timeframeLimits[state.timeframe]||92)
}
function processLiveQuote({last,bid,ask,exchangeTime=Date.now(),volume=0}={}){
  const price=Number(last)||((Number(bid)+Number(ask))/2);if(!Number.isFinite(price)||price<=0)return false;
  const receivedAt=Date.now();if(Number.isFinite(Number(bid))&&Number(bid)>0)state.quote.bid=Number(bid);if(Number.isFinite(Number(ask))&&Number(ask)>0)state.quote.ask=Number(ask);state.quote.last=price;state.quote.exchangeTime=Number(exchangeTime)||receivedAt;state.currentPrice=price;state.lastPriceAt=receivedAt;state.liveFailures=0;setMarketConnection('binance','Binance Spot');rollLiveCandle(price,state.quote.exchangeTime,volume);$('#currentPrice').textContent=formatPrice(price);evaluatePriceAlerts();updateOperation();runRobot();scheduleMarketDraw();return true
}
function scheduleMarketDraw(){if(scheduleMarketDraw.frame)return;scheduleMarketDraw.frame=requestAnimationFrame(()=>{scheduleMarketDraw.frame=0;if(priceOutlookCache.has(state.marketSymbol))renderPriceOutlook();drawChart()})}
function disconnectMarketStream(){clearTimeout(state.reconnectTimer);state.reconnectTimer=null;const stream=state.marketStream;state.marketStream=null;if(stream){stream.onclose=null;stream.close()}}
function connectMarketStream(){
  disconnectMarketStream();if(!state.marketSymbol||typeof WebSocket==='undefined')return;const symbol=state.marketSymbol.toLowerCase(),expected=state.marketSymbol;
  try{
    const stream=new WebSocket(`wss://stream.binance.com:443/stream?streams=${symbol}@aggTrade/${symbol}@bookTicker`);state.marketStream=stream;
    stream.onmessage=event=>{if(expected!==state.marketSymbol)return;try{const message=JSON.parse(event.data),data=message.data||message;if(data.e==='aggTrade')processLiveQuote({last:data.p,bid:state.quote.bid,ask:state.quote.ask,exchangeTime:data.T||data.E,volume:Number(data.q)||0});else if(data.e==='bookTicker'||('b'in data&&'a'in data))processLiveQuote({bid:data.b,ask:data.a,exchangeTime:Date.now()})}catch(error){/* o monitor de idade protege contra mensagens inválidas */}};
    stream.onerror=()=>stream.close();stream.onclose=()=>{if(state.marketStream===stream)state.marketStream=null;if(expected===state.marketSymbol){state.reconnectTimer=setTimeout(()=>connectMarketStream(),RECONNECT_MS)}};
  }catch(error){state.reconnectTimer=setTimeout(()=>connectMarketStream(),RECONNECT_MS)}
}
async function refreshLiveQuote(){
  if(state.liveRefreshing)return false;state.liveRefreshing=true;state.lastLiveRefresh=Date.now();try{const quote=await fetchBinance(`/api/v3/ticker/bookTicker?symbol=${encodeURIComponent(state.marketSymbol)}`);return processLiveQuote({bid:quote.bidPrice,ask:quote.askPrice,exchangeTime:Date.now()})}catch(error){state.liveFailures+=1;if(!hasFreshPrice())setMarketConnection('offline','Cotação indisponível · operações pausadas');return false}finally{state.liveRefreshing=false}}
function marketCatalog(){return state.markets.length?state.markets:assets}
function marketBySymbol(value){const key=String(value||'').toUpperCase();return marketCatalog().find(a=>a.marketSymbol===key||a.symbol===key)||assets.find(a=>a.marketSymbol===key||a.symbol===key)}
function changeLabel(value){const number=Number(value)||0;return`${number>=0?'+':''}${number.toFixed(2).replace('.',',')}%`}
function marketMatches(a,query){const q=query.trim().toLowerCase();return !q||`${a.symbol} ${a.marketSymbol} ${a.name}`.toLowerCase().includes(q)}

async function loadMarkets(force=false){
  if(state.marketsLoading)return;if(!force&&state.markets.length&&Date.now()-state.marketsLoadedAt<300000){renderMarkets($('#marketsSearch')?.value||'');return}
  state.marketsLoading=true;const table=$('#marketTable');if(table)table.innerHTML='<div class="market-loading"><i></i><strong>Consultando mercados</strong><small>Conectando à Binance Spot...</small></div>';
  try{
    const [info,tickers]=await Promise.all([fetchBinance('/api/v3/exchangeInfo'),fetchBinance('/api/v3/ticker/24hr')]);if(!Array.isArray(info?.symbols)||!Array.isArray(tickers))throw new Error('Resposta de mercados inválida');const tickerMap=new Map(tickers.map(t=>[t.symbol,t]));
    state.markets=info.symbols.filter(s=>s.quoteAsset==='USDT'&&s.status==='TRADING'&&s.isSpotTradingAllowed!==false).map(s=>{const t=tickerMap.get(s.symbol)||{};const price=Number(t.lastPrice);return{marketSymbol:s.symbol,symbol:s.baseAsset,name:knownAssetNames[s.baseAsset]||s.baseAsset,price,change:Number(t.priceChangePercent)||0,high:Number(t.highPrice)||price,low:Number(t.lowPrice)||price,volume:Number(t.quoteVolume)||0,icon:s.baseAsset.slice(0,2),color:coinColor(s.baseAsset),live:true}}).filter(a=>Number.isFinite(a.price)&&a.price>0).sort((a,b)=>b.volume-a.volume);
    state.marketsLoadedAt=Date.now();renderMarkets($('#marketsSearch')?.value||'');const active=marketBySymbol(state.marketSymbol);if(active?.live&&!hasFreshPrice()){updateAssetHeader(active);await loadMarketCandles();await refreshLiveQuote();connectMarketStream()}
  }catch(error){state.markets=[];renderMarkets($('#marketsSearch')?.value||'',true);setMarketConnection('offline','Binance indisponível · operações pausadas');if($('#marketsModal')?.open)showToast('API temporariamente indisponível','As operações permanecerão pausadas até a reconexão.','exit')}
  finally{state.marketsLoading=false;const query=$('#assetSearch')?.value||'';if(query)renderGlobalSearch(query)}
}

function renderMarkets(query='',fallback=false){
  const table=$('#marketTable');if(!table)return;const catalog=marketCatalog(),filtered=catalog.filter(a=>marketMatches(a,query));$('#marketCount').textContent=catalog.length;$('#marketsUpdated').textContent=fallback?'Modo local · tente atualizar':state.markets.length?`Atualizado às ${new Date(state.marketsLoadedAt).toLocaleTimeString('pt-BR',{hour:'2-digit',minute:'2-digit'})}`:'Favoritos locais';
  table.innerHTML=filtered.slice(0,80).map(a=>`<button class="market-row" data-market="${escapeHtml(a.marketSymbol)}"><span class="market-asset"><i class="market-coin" style="background:${a.color}">${escapeHtml(a.icon)}</i><b>${escapeHtml(a.name)}<small>${escapeHtml(a.symbol)}/USDT</small></b></span><strong class="market-number">${a.live?formatPrice(a.price):'—'}</strong><strong class="market-change ${a.change>=0?'up':'down'}">${a.live?changeLabel(a.change):'—'}</strong><span class="market-volume">${a.live?compactMoney(a.volume):'—'}</span></button>`).join('')||'<div class="market-empty"><strong>Nenhum mercado encontrado</strong><small>Tente pesquisar pelo símbolo, como BTC, ETH ou XRP.</small></div>';
  $$('.market-row[data-market]').forEach(row=>row.onclick=()=>selectMarket(row.dataset.market))
}

function updateAssetHeader(a){
  const preserveQuote=a.live&&state.marketSymbol===a.marketSymbol&&state.currentPrice>0&&state.lastPriceAt>0;state.asset=a.symbol;state.marketSymbol=a.marketSymbol;if(!preserveQuote){state.currentPrice=a.live?a.price:0;state.lastPriceAt=a.live?Date.now():0;state.quote={bid:0,ask:0,last:state.currentPrice,exchangeTime:0}}state.liveFailures=0;setMarketConnection(a.live?'binance':'loading',a.live?'Binance Spot':'Consultando Binance...');$('#assetName').textContent=a.name;$('#assetSymbol').textContent=`${a.symbol} / USDT`;$('#coinLogo').textContent=a.icon;$('#coinLogo').style.background=a.color;$('#currentPrice').textContent=a.live?formatPrice(state.currentPrice):'—';const change=$('.price-change');change.textContent=a.live?changeLabel(a.change):'—';change.classList.toggle('negative',a.change<0);$('#dailyPriceChange').textContent=a.live?`${a.change>=0?'+':''}${formatMoney(a.price*(a.change/100),2)} em 24h`:'—';$('#statHigh').textContent=a.live?formatPrice(a.high):'—';$('#statLow').textContent=a.live?formatPrice(a.low):'—';$('#statVolume').textContent=a.live?compactMoney(a.volume):'—';if(!state.order.active&&a.live){const entry=executionPrice('buy')||state.currentPrice,stop=entry*.98635;$('#entryPrice').textContent=formatPrice(entry);$('#stopPrice').textContent=formatPrice(stop)}calcTarget();renderAlerts();renderPriceOutlook(priceOutlookCache.get(state.marketSymbol),!priceOutlookCache.has(state.marketSymbol))
}

async function loadMarketCandles(){
  if(!Number.isFinite(state.currentPrice)||state.currentPrice<=0){candles=[];analysisCandles=[];setMarketConnection('offline','Sem preço Binance válido');drawChart();return false}
  try{const visibleLimit=timeframeLimits[state.timeframe]||92,historyLimit=320,rows=await fetchBinance(`/api/v3/klines?symbol=${encodeURIComponent(state.marketSymbol)}&interval=${binanceIntervals[state.timeframe]||'15m'}&limit=${historyLimit}`);if(!Array.isArray(rows))throw new Error('Resposta de candles inválida');const parsed=rows.map(k=>({time:Number(k[0]),open:Number(k[1]),high:Number(k[2]),low:Number(k[3]),close:Number(k[4]),volume:Number(k[5])})).filter(c=>[c.open,c.high,c.low,c.close,c.volume].every(Number.isFinite)&&c.high>=c.low&&c.volume>=0);if(parsed.length<Math.min(24,visibleLimit))throw new Error('Candles insuficientes');analysisCandles=parsed;candles=parsed.slice(-visibleLimit).map(c=>({...c}));resetChartView(false);mapiCache.key='';trendMapCache.key='';state.currentPrice=candles.at(-1).close;state.liveFailures=0;$('#currentPrice').textContent=formatPrice(state.currentPrice);currentMapiResult(true);drawChart();loadPriceOutlook()}
  catch(error){candles=[];analysisCandles=[];mapiCache={key:'',result:null,computedAt:0};setMarketConnection('offline','Candles Binance indisponíveis');drawChart();showToast('Candles indisponíveis','Robô e operações foram pausados; nenhum preço local será utilizado.','exit');return false}
}

async function selectMarket(value){let a=marketBySymbol(value);if(!a||state.marketChanging)return;if(state.order.active&&state.order.marketSymbol&&state.order.marketSymbol!==a.marketSymbol){showToast('Operação em andamento','Encerre a posição atual antes de trocar de mercado.','exit');return}state.marketChanging=true;disconnectMarketStream();if(state.robot.pendingSignal)cancelSignalEntry(true);state.robot.signalPrompted=false;try{if(!a.live){await loadMarkets(true);a=marketBySymbol(value)}if(!a?.live)throw new Error('Mercado Binance indisponível');updateAssetHeader(a);$('#searchResults').classList.remove('show');$('#assetSearch').value='';if($('#marketsModal')?.open)$('#marketsModal').close();const loaded=await loadMarketCandles();if(loaded===false)throw new Error('Candles Binance indisponíveis');await refreshLiveQuote();connectMarketStream();renderRobotUI();showToast(`${a.symbol}/USDT selecionado`,'Preço e candles carregados da Binance Spot.')}catch(error){setMarketConnection('offline','Binance indisponível · operações pausadas');showToast('Mercado indisponível',error?.message||'Tente novamente em instantes.','exit')}finally{state.marketChanging=false;if(state.robot.active&&hasFreshPrice())runRobot()}}
function chooseAsset(symbol){return selectMarket(symbol)}

